#Requires -Version 5.1<#.SYNOPSIS    Bootstrap script for Vendor Manager on Windows..DESCRIPTION    Checks for Python and Tesseract, creates a virtual environment,    and installs dependencies.#>$ErrorActionPreference = "Stop"# Parse arguments$SkipSystem = $false$RunApp = $falseforeach ($arg in $args) {    if ($arg -eq "--skip-system") { $SkipSystem = $true }    if ($arg -eq "--run-app") { $RunApp = $true }}Write-Host "========================================" -ForegroundColor CyanWrite-Host "  Vendor Manager - Windows Setup" -ForegroundColor CyanWrite-Host "========================================" -ForegroundColor CyanWrite-Host ""# Step 1: Check for PythonWrite-Host "[1/4] Checking for Python..." -ForegroundColor Yellowtry {    $pythonPath = Get-Command python -ErrorAction SilentlyContinue    if (-not $pythonPath) {        throw "Python is not installed or not in PATH."    }    Write-Host "   Found: $$($$pythonPath.Source)" -ForegroundColor Green    $pythonVersion = python --version    Write-Host "   Version: $pythonVersion" -ForegroundColor Green} catch {    Write-Host "   ERROR: Python not found. Please install Python 3.9+ from https://www.python.org/downloads/" -ForegroundColor Red    Write-Host "   IMPORTANT: Check 'Add Python to PATH' during installation." -ForegroundColor Yellow    exit 1}# Step 2: Check for Tesseract OCRWrite-Host ""Write-Host "[2/4] Checking for Tesseract OCR..." -ForegroundColor Yellow$tesseractFound = $falsetry {    $tesseractPath = Get-Command tesseract -ErrorAction SilentlyContinue    if ($tesseractPath) {        Write-Host "   Found: $$($$tesseractPath.Source)" -ForegroundColor Green        $tesseractFound = $true    }} catch {    # Not found}if (-not $tesseractFound) {    if ($SkipSystem) {        Write-Host "   [WARN] Skipping Tesseract installation by request." -ForegroundColor Magenta        Write-Host "   OCR feature will not work without Tesseract." -ForegroundColor Magenta    } else {        Write-Host "   WARNING: Tesseract not found in PATH." -ForegroundColor Red        Write-Host "   Tesseract is REQUIRED for the OCR scanning feature." -ForegroundColor Red        Write-Host ""                # Try winget first        $wingetAvailable = Get-Command winget -ErrorAction SilentlyContinue        if ($wingetAvailable) {            Write-Host "   Attempting to install via winget..." -ForegroundColor Yellow            try {                winget install -e --id UB-Mannheim.TesseractOCR --silent                Write-Host "   Tesseract installed successfully via winget!" -ForegroundColor Green                $tesseractFound = $true            } catch {                Write-Host "   winget install failed, trying manual instructions..." -ForegroundColor Yellow            }        }                if (-not $tesseractFound) {            $installChoice = Read-Host "Do you want to open the Tesseract download page? (Y/N)"            if ($installChoice -eq "Y" -or $installChoice -eq "y") {                Start-Process "https://github.com/UB-Mannheim/tesseract/wiki"                Write-Host ""                Write-Host "   INSTRUCTIONS:" -ForegroundColor Cyan                Write-Host "   1. Download the latest installer (e.g., tesseract-ocr-w64-setup-5.x.x.exe)." -ForegroundColor White                Write-Host "   2. Run the installer." -ForegroundColor White                Write-Host "   3. IMPORTANT: During installation, CHECK the box to 'Add Tesseract to PATH'." -ForegroundColor Yellow                Write-Host "   4. Restart this script after installation." -ForegroundColor White                exit 1            } else {                Write-Host "   Aborting. Tesseract is required for OCR." -ForegroundColor Red                exit 1            }        }    }}# Step 3: Create virtual environmentWrite-Host ""Write-Host "[3/4] Creating virtual environment..." -ForegroundColor Yellowtry {    if (Test-Path ".venv") {        Write-Host "   Removing existing .venv..." -ForegroundColor Yellow        Remove-Item -Recurse -Force .venv    }    python -m venv .venv    Write-Host "   Virtual environment created." -ForegroundColor Green} catch {    Write-Host "   ERROR: Failed to create virtual environment." -ForegroundColor Red    exit 1}# Step 4: Install Python dependenciesWrite-Host ""Write-Host "[4/4] Installing Python dependencies..." -ForegroundColor Yellowtry {    .\.venv\Scripts\python.exe -m pip install --upgrade pip    .\.venv\Scripts\python.exe -m pip install -r requirements.txt    Write-Host "   Dependencies installed successfully!" -ForegroundColor Green} catch {    Write-Host "   ERROR: Failed to install dependencies." -ForegroundColor Red    Write-Host $_.Exception.Message    exit 1}Write-Host ""Write-Host "========================================" -ForegroundColor CyanWrite-Host "  Setup Complete!" -ForegroundColor CyanWrite-Host "========================================" -ForegroundColor CyanWrite-Host ""Write-Host "To activate the environment and run the app:" -ForegroundColor WhiteWrite-Host "  .\.venv\Scripts\Activate.ps1" -ForegroundColor CyanWrite-Host "  python vendor_manager.py" -ForegroundColor CyanWrite-Host ""Write-Host "Or run directly:" -ForegroundColor WhiteWrite-Host "  .\.venv\Scripts\python.exe vendor_manager.py" -ForegroundColor CyanWrite-Host ""if ($RunApp) {    Write-Host "Launching Vendor Manager..." -ForegroundColor Yellow    .\.venv\Scripts\python.exe vendor_manager.py}